const response = $input.first().json || {};
const countries = Array.isArray(response.countries) ? response.countries : [];

const supported = countries.length ? countries : ['United Kingdom', 'Canada', 'United States', 'Australia'];

return supported.map((country) => ({
  json: {
    country,
    source_url: `https://www.numbeo.com/cost-of-living/country_result.jsp?country=${encodeURIComponent(country)}&displayCurrency=INR`
  }
}));

const rows = $input.all();
const listings = [];

const fallback = {
  'United Kingdom': 90000,
  'Canada': 70000,
  'United States': 110000,
  'Australia': 85000
};

for (const [idx, row] of rows.entries()) {
  const j = row.json || {};
  const country = j.country || 'Unknown';
  const raw = (j.body || j.data || '').toString();
  const cleaned = raw.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');

  const rentMatch = cleaned.match(/Apartment.*City Centre[^0-9]*([0-9][0-9,]*)/i);
  const parsed = rentMatch ? Number(rentMatch[1].replace(/,/g, '')) : null;
  const priceInr = Number.isFinite(parsed) && parsed > 0 ? parsed : (fallback[country] || 75000);

  listings.push({
    id: `n8n_${country.toLowerCase().replace(/[^a-z0-9]+/g, '_')}_${idx + 1}`,
    title: `Student accommodation benchmark - ${country}`,
    country,
    price_inr: Math.round(priceInr),
    distance_km: 2.5,
    amenities: ['Wi-Fi', 'Laundry', 'Study Desk'],
    image_url: null,
    available_from: 'Monthly rolling',
    student_friendly: true
  });
}

return [{ json: { listings } }];
